The fix: In each story file, change the meta type pattern from:
```tsx
const meta = {
  component: SomeChart,
} satisfies Meta<typeof SomeChart>;

export default meta;
type Story = StoryObj<typeof meta>;
```

To:
```tsx
const meta: Meta = {
  component: SomeChart,
};

export default meta;
type Story = StoryObj<typeof meta>;
